"""
MKT Original Commentary — Matthew chapters 9–10
Run: python3 scripts/zc-original-matthew-9-10.py

Source data used:
- data/interlinear/matthew.json
- data/translation/draft/mediating/matthew.json
- data/commentary/mkt-original/matthew.json (existing ch1-8 carried forward)

Key decisions in this range:
- aphientai (9:2): present passive "are forgiven" — not a simple declaration but
  an ongoing state being effected in the moment
- sōzō (9:21-22): used for physical healing and spiritual salvation — same word;
  translation "healed" in MKT but the broader register is preserved in commentary
- kōphos (9:32): deaf or mute — context determines which sense; here mute
- esplanchnisthē (9:36): strongest Greek word for compassion, visceral/gut-level
- apostolos (10:2): first use of this term in Matthew; title not just description
- dōrean (10:8): given as gift, without price — economic dimension of the mission
- akeraios (10:16): unmixed, pure — not naive but uncorrupted by compromise
- machaira (10:34): short sword, cutting instrument — not the large rhomphaia
  (10:34 sword-not-peace saying: the division Jesus causes is not his goal but his effect)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

MATTHEW = {
  "9": {
    "1": '<p><strong>embas eis ploion diepersen</strong> — stepping into a boat he crossed over — <em>embas</em> aorist participle of <em>embainō</em>; <em>diepersen</em> aorist of <em>diaperaō</em> (to cross over completely): a purposeful journey back. <em>Eis tēn idian polin</em> — to his own town: Capernaum (cf. 4:13), which Matthew treats as Jesus\'s base of operations. The return frames the healing of the paralytic that follows as a homecoming demonstration.</p>',
    "2": '<p><strong>idōn tēn pistin autōn</strong> — seeing their faith — <em>idōn</em> aorist participle of <em>horaō</em>: Jesus perceives the faith not just of the paralytic but of the plural <em>autōn</em> (them), the group who brought him. <em>Tharsei teknon</em> — take heart, child (<em>teknon</em>, child: an affectionate address expressing personal relationship). <em>Aphientai sou hai hamartiai</em> — your sins are being forgiven (<em>aphientai</em> present passive: the forgiving is happening now, not merely declared complete). The present tense is significant: not "were forgiven" but "are forgiven in this moment."</p>',
    "3": '<p><strong>houtoi blasphēmei</strong> — this man is blaspheming — the scribes\' accusation is theologically precise: forgiveness of sins was recognized as a divine prerogative (cf. Isa 43:25; Ps 103:3); claiming to exercise it is, on their framework, either divine authority or blasphemy. The scribes do not say Jesus is wrong about the man\'s forgiveness; they say he has no right to announce it. <em>En heautois</em> — within themselves: the accusation is unspoken, a thought Jesus perceives (v.4).</p>',
    "4": '<p><strong>gnous de ho Iēsous tas enthymēseis autōn</strong> — knowing their deliberations/thoughts (<em>enthymēseis</em>, from <em>enthymeomai</em>: deep inner deliberation, the reasoning process of the heart, not surface thought) — <em>gnous</em> aorist participle of <em>ginōskō</em>: Jesus\'s knowledge of their internal reasoning is direct, not inferred from facial expressions. <em>Eis tas kardias hymōn</em> — in your hearts: the heart (<em>kardia</em>) as the seat of deliberation reinforces that the scribes\' error is not intellectual but volitional.</p>',
    "5": '<p><strong>ti gar estin eukopōteron</strong> — for which is easier (<em>eukopoteros</em>, comparative of <em>eukopos</em>: easy, requiring little labor) — the question is rhetorical and exposes the asymmetry: saying "your sins are forgiven" is unverifiable (no physical change occurs); saying "get up and walk" is immediately verifiable. If Jesus can do the harder (visible) thing, it demonstrates the authority behind the easier-to-say (invisible) thing. The miracles are epistemological evidence.</p>',
    "7": '<p><strong>kai ēgerthē</strong> — and he arose (<em>egeirō</em> aorist passive: to be raised up, the same verb used for resurrection; the healing terminology anticipates resurrection-language throughout Matthew) — <em>apēlthen eis ton oikon autou</em> (went to his house): the brevity of the report is striking; Matthew does not narrate the mechanics of the healing but the completed result. The aorist marks the action as complete and decisive.</p>',
    "8": '<p><strong>idontes de hoi ochloi ephobēthēsan</strong> — seeing this, the crowds were afraid (<em>phobeō</em> aorist passive: a sudden awe-filled fear) — <em>edoxasan ton theon</em> (glorified God): the fear produces doxology, not paralysis. <em>Ton donta exousian toiautēn tois anthrōpois</em> — the one who gave such authority to human beings: the crowd\'s conclusion is partial; they see "authority given to human beings" but do not yet perceive the divine identity of the one exercising it. The theology of the crowds remains incomplete.</p>',
    "9": '<p><strong>Maththaion legomenon kathēmenon epi to telōnion</strong> — a man named Matthew sitting at the tax collector\'s booth — <em>telōnion</em> (the toll-collection booth, the official station for collecting customs dues); <em>kathēmenon</em> present participle: he was seated, engaged in his work, when the call came. <em>Akolouthei moi</em> — follow me (present imperative: begin following and continue). <em>Anastas ēkolouthēsen autō</em> — rising he followed him — <em>anastas</em> aorist participle (having risen): the immediacy of response echoes 4:20,22 (the fishermen disciples).</p>',
    "10": '<p><strong>anakeiomnou autou en tē oikia</strong> — while he was reclining at table in the house (<em>anakeimai</em>, to recline at a meal, the formal dining posture) — <em>polloi telōnai kai hamartōloi</em> (many tax collectors and sinners): <em>telōnai</em> (toll-collectors, collaborators with Herod/Rome; despised both as extortioners and as ritually unclean from constant Gentile contact) and <em>hamartōloi</em> (sinners, those either openly transgressing Torah or in professions that made observance impossible). <em>Synanekeninto</em> — were reclining together: shared table-fellowship implied social and covenantal solidarity.</p>',
    "11": '<p><strong>dia ti meta tōn telōnōn kai hamartōlōn esthiei ho didaskalos hymōn</strong> — why does your teacher eat with tax collectors and sinners — the question is addressed to the disciples, not Jesus; the Pharisees use the social pressure of questioning subordinates rather than confronting the teacher directly. <em>Didaskalos</em> (teacher): the Pharisees acknowledge Jesus\'s role while challenging his practice. Table fellowship in Second Temple Judaism marked social and religious boundaries; eating with the unclean signaled solidarity with them.</p>',
    "12": '<p><strong>ou chreian echousin hoi ischyontes iatrou</strong> — the strong do not have need of a physician — <em>ischyontes</em> present participle of <em>ischyō</em> (to be strong, to be well): those who are currently strong. The analogy reframes the question: a physician eating with the sick is not contaminated but is practicing medicine. <em>Hoi kakōs echontes</em> — those who are ill (having it badly): the idiom for illness sets up the mission-statement of v.13. The implication: the Pharisees misidentify who needs the physician and therefore misread the physician\'s table practice.</p>',
    "14": '<p><strong>dia ti hēmeis kai hoi Pharisaioi nēsteuomen polla</strong> — why do we and the Pharisees fast often (<em>nēsteuō</em>, present: ongoing fasting practice; <em>polla</em> = much, often) — John\'s disciples and the Pharisees share a fasting practice despite their theological differences, presenting a united front of puzzlement. <em>Hoi de mathētai sou ou nēsteuousin</em> — but your disciples do not fast: the contrast is between communities defined by their devotional disciplines. Jesus\'s response offers a theology of the eschatological moment that explains the discrepancy.</p>',
    "15": '<p><strong>mē dynasthai penthein hoi huioi tou nymphōnos</strong> — can the sons of the bridal chamber mourn (<em>pentheō</em> as in the second Beatitude; now applied to the disciples\' non-fasting) — <em>hoi huioi tou nymphōnos</em> (the sons of the bridal chamber, the wedding guests who attend the groom): a Semitic idiom for those intimately associated with the bridegroom. <em>Heōs hotou met autōn estin ho numphios</em> — as long as the bridegroom is with them. <em>Eleusontai de hēmerai hotan aparthē ap autōn ho numphios, kai tote nēsteusousin</em> — but days will come when the bridegroom is taken from them (<em>aparthē</em> aorist passive subjunctive of <em>apairō</em>: taken away, the language of violent removal), and then they will fast. The saying anticipates the passion without naming it.</p>',
    "16": '<p><strong>epiblemma rhakous agnaptou</strong> — a patch of unprocessed cloth (<em>agnaptos</em>, not yet fulled or shrunk: raw, undressed fabric) — the patch is the new element that is problematic, not the garment. <em>Airei gar to plērōma autou apo tou himatiou</em> — for the patch takes away (<em>airō</em>) its fullness/filling from the garment: the new patch, shrinking in the wash, pulls against the old garment, making the tear worse. The parable argues that Jesus\'s ministry is not a patch to be applied to existing religious structures but something categorically new requiring new containers.</p>',
    "17": '<p><strong>oinos neos eis askous palaiois</strong> — new wine into old wineskins (<em>askoi</em>, wineskins made of animal hide) — old wineskins are already stretched from previous fermentation; new wine still fermenting generates pressure that will burst them. <em>Rēgnyntai hoi askoi kai ho oinos ekchynetai kai hoi askoi apollyntai</em> — the skins burst and the wine spills out and the skins are destroyed (<em>apollymi</em>, the same word for perishing/losing): double loss. <em>Oinos neos eis askous kainous</em> — new wine into new wineskins: <em>kainos</em> (new in quality, fresh) vs. <em>neos</em> (new in time). The new wine of the kingdom requires the new wineskins of the new covenant community.</p>',
    "18": '<p><strong>archōn eis proselthōn prosekynei autō</strong> — one ruler came and was bowing before him (<em>prosekynei</em> imperfect: was continuing to bow/worship in ongoing prostration) — <em>archōn</em> (ruler, official): Luke 8:41 identifies him as a synagogue ruler (<em>archisyagōgos</em>). <em>Hē thygatēr mou arti eteleutēsen</em> — my daughter has just died (<em>arti</em>, just now; <em>teleutaō</em> aorist: has come to her end). <em>Alla elthōn epithes tēn cheira sou ep autēn kai zēsetai</em> — but come and place your hand on her and she will live: the petition presupposes a power over death that goes beyond normal healing expectation.</p>',
    "19": '<p><strong>egertheis ho Iēsous ēkolouthei autō</strong> — Jesus, having risen, was following him — <em>egertheis</em> aorist participle (having risen, i.e., from table or from his position): the same verb as the paralytic\'s rising in v.7. <em>Ēkolouthei</em> imperfect: was following, in process; notably Matthew here describes Jesus using the discipleship-verb (<em>akoloutheo</em>) in Jesus\'s own action of following the ruler — a remarkable reversal of the usual direction.</p>',
    "20": '<p><strong>gynaik haimorrousa dōdeka etē</strong> — a woman hemorrhaging for twelve years — <em>haimorrousa</em> present active participle of <em>haimorroō</em> (to flow with blood): the present marks the continuous, unceasing nature of her condition. Twelve years of hemorrhage would have rendered her perpetually unclean under Lev 15:25-27, barring her from the Temple, from marriage, and from normal social contact. <em>Proselthōn opisthen ēpsato tou kraspedou</em> — approaching from behind she touched the hem (<em>kraspedon</em>, fringe/tassel of a garment, possibly the tassels of Num 15:38-39): approaching from behind conceals her unclean status.</p>',
    "21": '<p><strong>elegen gar en heautē</strong> — for she was saying within herself — <em>en heautē</em> (within herself, in her own interior): the speech is internal, not spoken aloud. <em>Ean monon hapsōmai tou himatiou autou sōthēsomai</em> — if I only touch his garment I will be saved/healed (<em>sōthēsomai</em> future passive of <em>sōzō</em>): the MKT renders this "healed" but <em>sōzō</em> is Matthew\'s word for eschatological salvation as well as physical restoration. The woman\'s faith operates in the register of the word\'s full semantic range: she expects rescue.</p>',
    "22": '<p><strong>epistrapheis kai idōn autēn eipen</strong> — turning and seeing her he said — <em>epistrapheis</em> aorist passive participle of <em>strephō</em> (to turn, be turned): a deliberate turning toward her. <em>Tharsei thygate</em> — take heart, daughter (<em>thygate</em>: the same affectionate address as <em>teknon</em> in v.2): a personal word before the pronouncement. <em>Hē pistis sou sesōken se</em> — your faith has saved/healed you — <em>sesōken</em> perfect active: it has saved and the saving stands completed. <em>Kai esōthē hē gynē apo tēs hōras ekeinēs</em> — and the woman was saved/healed from that hour: aorist passive marking the moment of completion.</p>',
    "23": '<p><strong>tous aulētas kai ton ochlon thorybоumenon</strong> — the flute players and the noisy crowd (<em>aulētēs</em>, flute player; <em>thorybeomai</em>, to be in an uproar, to create a commotion) — in Jewish custom, even the poorest families hired professional mourners and musicians at a death; the <em>aulētai</em> would be playing dirge-music. The presence of formal mourning-professionals establishes that the girl is understood to be genuinely dead by those present.</p>',
    "24": '<p><strong>anacōreite ou gar apethanen to korasion alla katheudei</strong> — withdraw, for the girl has not died but is sleeping (<em>anacōreō</em>, withdraw; <em>katheudō</em>, to sleep — also used as a euphemism for death in Jewish and Christian usage) — <em>kategelōn autou</em> (they laughed at him — <em>katagelō</em>, to laugh down at, deride): the crowd\'s laughter is not disrespect but certainty; they know she is dead. Jesus\'s statement is either metaphor (the death is temporary, like sleep) or a claim that from his perspective death has this quality. Both may be simultaneously true.</p>',
    "25": '<p><strong>ekblēthentos de tou ochlou eiselthōn ekratēsen tēs cheiros autēs</strong> — when the crowd was put outside, entering he took her hand (<em>ekballō</em> aorist passive: the crowd was thrown out — the same verb as exorcism; <em>krateō</em> aorist: grasped firmly) — <em>kai ēgerthē to korasion</em> (and the girl arose — <em>ēgerthē</em> aorist passive of <em>egeirō</em>, the resurrection verb): the brevity of the narrative matches the immediacy of the event. No word of command is recorded in Matthew; the touch alone suffices.</p>',
    "26": '<p><strong>kai exēlthen hē phēmē autē eis holēn tēn gēn ekeinēn</strong> — this report went out into all that land — <em>phēmē</em> (report, reputation, from <em>phēmi</em>, to say): the fame that Jesus repeatedly tries to limit (8:4; 9:30) spreads despite his restrictions. <em>Holēn tēn gēn ekeinēn</em> (all that land, the surrounding region): the news cannot be contained to the house or town.</p>',
    "27": '<p><strong>huie Dauid eleēson hēmas</strong> — Son of David, have mercy on us — the blind men use the Davidic Messiah title (<em>huios Dauid</em>), which carries the expectation of the Messianic heir who would heal and restore Israel (Isa 29:18; 35:5). This is Matthew\'s first significant use of the title since the genealogy (1:1); it will reappear at 12:23; 15:22; 20:30-31; 21:9,15. <em>Eleēson</em> aorist imperative of <em>eleō</em>: grant mercy, show covenant loyalty.</p>',
    "28": '<p><strong>pisteute hoti dynasthai touto poiēsai</strong> — do you believe that I am able to do this (<em>pisteuo</em> present: are you maintaining this belief?) — Jesus asks the question privately, indoors, after the public pursuit. <em>Dynasthai</em> (to be able): the question targets the object of their faith — not whether they will be healed, but whether Jesus specifically has the power. <em>Nai kyrie</em> — yes, Lord: <em>kyrie</em> (Lord) is their address, matching the centurion and the storm-disciples; the blind recognize what the crowds did not.</p>',
    "29": '<p><strong>kata tēn pistin hymōn genēthētō hymin</strong> — according to your faith let it be done to you — <em>kata</em> (according to, in proportion to): the healing corresponds to the faith, not as a reward for it but as its completion. <em>Genēthētō</em> aorist passive imperative of <em>ginomai</em>: let it happen, let it come to be. The statement is remarkable: faith is the measure by which the miracle is sized. This principle recurs in 8:13 (the centurion: "as you believed") and 15:28 (the Canaanite woman: "as you desire").</p>',
    "30": '<p><strong>enebrimēthē autois ho Iēsous</strong> — Jesus sternly warned them (<em>embrimaomai</em>: to snort with emotion, to charge sternly, to rebuke with intensity — the word is used for strong emotional reaction, including indignation; Mark uses it for Jesus\'s reaction before raising Lazarus, John 11:33) — <em>horate mēdeis ginōsketō</em> (see that no one knows: present imperative + subjunctive: an ongoing prohibition). The severity of the warning underlines the messianic secrecy motif: Jesus is managing the pace and nature of disclosure about his identity.</p>',
    "31": '<p><strong>hoi de exelthontes diephēmisan auton en holē tē gē ekeinē</strong> — but going out they spread his fame throughout all that land — <em>diaphēmizō</em> (to spread a report widely, to publicize): the disobedience to the command of v.30 mirrors the spreading fame after the ruler\'s daughter (v.26). The inability to suppress news of miraculous healing is a structural theme in Matthew\'s miracle chain (ch8-9): the disciples leak the news despite the charge.</p>',
    "32": '<p><strong>kōphon daimonizomenon</strong> — a mute/deaf demon-possessed man (<em>kōphos</em>: the word covers both deafness and muteness; context — the man not speaking — suggests muteness here) — the case is brought to Jesus by others, as in 8:16. This is the fourth major miracle in the sequence of ch9 (paralytic, hemorrhaging woman/Jairus\'s daughter, blind men, mute demoniac), each addressing a different incapacity that Second Temple Judaism associated with the messianic age.</p>',
    "33": '<p><strong>ekblēthentos de tou daimoniou elalēsen ho kōphos</strong> — when the demon was driven out the mute man spoke — the exorcism and the cure are simultaneous: the demonic cause removed, the human capacity restored. <em>Ethaumasan hoi ochloi legontes oudepote ephanthē houtōs en tō Israēl</em> — the crowds marveled saying: never has it appeared thus in Israel (<em>phainō</em> aorist passive: never has it been seen; <em>oudepote</em> as in 7:23: never at any time). The cumulative effect of the miracle-chain provokes a climactic statement of unprecedented occurrence.</p>',
    "34": '<p><strong>hoi de Pharisaioi elegon en tō archonti tōn daimoniōn ekballei ta daimonia</strong> — but the Pharisees were saying: by the ruler of demons he drives out demons — <em>elegon</em> imperfect: they kept saying, making this a sustained accusation. <em>Ho archōn tōn daimoniōn</em> (the ruler of the demons): the claim that exorcistic power comes from demonic source rather than divine; Jesus addresses this explicitly in 12:25-29. The crowd\'s amazement (v.33) and the Pharisees\' accusation (v.34) divide the audience into two responses that will persist throughout the Gospel.</p>',
    "35": '<p><strong>periēgen ho Iēsous tas poleis pasas kai tas kōmas</strong> — Jesus went around all the towns and villages (<em>periagō</em> imperfect: was continuously going about) — the three present participles (<em>didaskōn</em>, <em>kērysson</em>, <em>therapeuōn</em>: teaching, proclaiming, healing) describe the ongoing character of his itinerant ministry. <em>Kēryssōn to euangelion tēs basileias</em> — proclaiming the gospel of the kingdom: <em>euangelion</em> (good news, the announcement of victorious news by a herald) + <em>tēs basileias</em> (of the kingdom). The summary verse (cf. 4:23) uses the same triadic description of Jesus\'s ministry.</p>',
    "36": '<p><strong>esplanchnisthē peri autōn</strong> — he had compassion on them (<em>splagchnizomai</em>, from <em>splanchnon</em>/intestines, the visceral seat of emotion; the strongest Greek word for compassion, meaning gut-level, visceral feeling for another\'s suffering) — <em>eskylmenoi kai errimmenoi</em> (harassed and helpless/cast down: <em>skyllomai</em>, to be harrassed, worn out; <em>rhiptō</em> perfect passive: thrown about, cast down like discarded things). <em>Hōsei probata mē echonta poimena</em> — like sheep not having a shepherd: echoing Num 27:17; 1 Kgs 22:17; Ezek 34:5 — the image of Israel without faithful shepherding.</p>',
    "37": '<p><strong>ho men therismos polys hoi de ergatai oligoi</strong> — the harvest is plentiful but the workers are few — <em>therismos</em> (harvest) shifts the metaphor from sheep/shepherd (v.36) to harvest: the compassion-move produces a harvest-assessment. <em>Polys</em>/<em>oligoi</em> (plentiful/few): the asymmetry between need and available workers is the premise for the prayer of v.38. Harvest in Jewish eschatological imagery (Joel 3:13; Isa 27:12) carried end-time associations of gathering the nations.</p>',
    "38": '<p><strong>deēthēte oun tou kyriou tou therismou</strong> — therefore pray/beseech the Lord of the harvest (<em>deomai</em> aorist passive imperative: to beseech, petition urgently) — <em>tou kyriou tou therismou</em> (the Lord of the harvest): God is the owner of the harvest field and the ultimate agent of mission; workers are sent by him, not self-commissioned. <em>Hopōs ekbalē ergas eis ton therismon autou</em> — that he might send out workers into his harvest (<em>ekballō</em> aorist subjunctive: to throw out, drive out, send out forcefully — the same verb for exorcism; mission is as urgent as exorcism). The prayer becomes the transition into the sending of the twelve in ch10.</p>'
  },
  "10": {
    "1": '<p><strong>kai proskalesamenos tous dōdeka mathētas</strong> — calling to himself the twelve disciples (<em>proskaleomai</em> aorist middle: summoning to oneself; the middle voice emphasizes the personal initiative of Jesus) — <em>edōken autois exousian</em> (gave them authority — <em>exousia</em>, the same word as 7:29; 9:6,8): the twelve receive delegated authority, not independent power. <em>Pneumatōn akathartōn</em> (over unclean spirits) and <em>pasan noson kai pasan malakian</em> (every disease and every weakness): the authority given mirrors Jesus\'s own practice in 9:35.</p>',
    "2": '<p><strong>tōn de dōdeka apostolōn ta onomata</strong> — the names of the twelve apostles (<em>apostolos</em>, sent one, from <em>apostellō</em>, to send off with a commission) — this is Matthew\'s first and only explicit use of the title <em>apostolos</em> for the twelve (cf. Mark 6:30; Luke uses it frequently). The title defines them by their function: they are sent ones, commissioned agents. The list begins with <em>prōtos Simōn ho legomenos Petros</em> (first, Simon who is called Peter) — <em>prōtos</em> marks Peter\'s precedence in the list, not necessarily in rank.</p>',
    "3": '<p><strong>Philippos kai Bartholomaios</strong> — the names continue; <em>Maththaios ho telōnēs</em> — Matthew the tax collector: uniquely in Matthew\'s list, Matthew is identified by his former occupation (the other Gospels simply list his name), a mark of the self-identification of a Gospel written by the same person who was called in 9:9. The profession is both a confession and a commendation of grace: a tax collector among the sent ones.</p>',
    "4": '<p><strong>Simōn ho Kananaios kai Ioudas ho Iskariōtēs</strong> — Simon the Zealot (<em>Kananaios</em> from Aramaic <em>qan\'an</em>, zealous, probably referring to the Zealot movement or simply to intense piety) and Judas Iscariot — <em>ho kai paradous auton</em> (the one who also betrayed him): Judas is introduced with the shadow of betrayal already attached. The list ends where the passion narrative will end. <em>Iskariōtēs</em>: possibly "man of Kerioth" (a Judean town) or from Aramaic <em>seqarya</em> (assassin), the etymology uncertain.</p>',
    "5": '<p><strong>eis hodon ethnōn mē apelthēte kai polin Samaritōn mē eiselthēte</strong> — do not go on a road of Gentiles and do not enter a Samaritan city — the restriction is geographical but carries covenantal significance: the first mission is concentrated on Israel, not as an ethnic preference but as the covenant-priority of fulfilling the promises to the lost sheep of the house of Israel (v.6) before the universal mission (28:19). The restriction is temporary; it is lifted at the resurrection.</p>',
    "6": '<p><strong>ta probata ta apolōlota oikou Israēl</strong> — the lost sheep of the house of Israel (<em>apolōlota</em> perfect passive participle of <em>apollymi</em>: the sheep that have been lost, currently in the state of lostness) — the same compassion-image as 9:36 (sheep without a shepherd) but with the perfect tense adding the weight of completed lostness: they are not merely wandering but definitively lost. The phrase echoes Ezek 34\'s indictment of Israel\'s shepherds who let the flock be scattered.</p>',
    "7": '<p><strong>ēggiken hē basileia tōn ouranōn</strong> — the kingdom of the heavens has drawn near (<em>ēggiken</em> perfect of <em>engizō</em>: has come near and remains near, the perfect combining completed approach with present proximity) — the identical proclamation as John the Baptist (3:2) and Jesus himself (4:17): the twelve proclaim the same message as their sender. <em>Poreuomenoi de kēryssete legontes</em> — going, proclaim saying: the proclamation accompanies movement, not a fixed location.</p>',
    "8": '<p><strong>astheountas therapeute, nekrous egeirete, leprous katharizete, daimonia ekballete</strong> — heal the sick, raise the dead, cleanse lepers, drive out demons — four aorist imperatives of equal weight; the raising of the dead is listed without emphasis as one item in the series. <em>Dōrean elabete dōrean dote</em> — freely (<em>dōrean</em>, as a gift, gratis, without price: the adverbial accusative of <em>dōron</em>) you received; freely give: the disciples received their authority and gifts without payment to Jesus; they are to extend the same terms. The sentence forbids the commercialization of the miraculous.</p>',
    "9": '<p><strong>mē ktēsēsthe chryson mēde argyron mēde chalkon eis tas zōnas hymōn</strong> — do not acquire (<em>ktaomai</em> aorist middle subjunctive: to acquire for oneself, to make one\'s own possession) gold or silver or copper in your belts — the descending order (gold → silver → copper) covers all monetary value. The belt (<em>zōnē</em>) was used as a money-belt in ancient travel. The prohibition is not against having money but against making the mission financially self-providing; dependence on the generosity of those receiving the gospel was itself part of the proclamation.</p>',
    "10": '<p><strong>mē pēran eis hodon mēde dyo chitōnas mēde hypodēmata mēde rhabdon</strong> — no travel bag for the road nor two tunics nor sandals nor a staff — the list enumerates the standard equipment of an ancient traveler; the disciples are sent without the normal self-sufficiency of travel. <em>Axios gar ho ergatēs tēs trophēs autou</em> — for the worker is worthy of his food (<em>axios</em>, worthy, deserving; <em>trophē</em>, nourishment): the theological principle underlying the prohibition. The community receiving the proclamation owes provision to those who proclaim.</p>',
    "11": '<p><strong>exetasate tis en autē axios estin</strong> — inquire who in it is worthy (<em>exetazō</em>: to examine thoroughly, investigate; not a casual inquiry but a deliberate assessment of receptivity and hospitality) — <em>axios</em> (worthy): the same word as 10:10; the worthiness of the worker and the worthiness of the host are parallel. <em>Kakeikei meinate heōs an exelthēte</em> — and there remain until you leave: the instruction against house-hopping preserves the integrity of the mission by not treating hospitality as a ladder of social advancement.</p>',
    "12": '<p><strong>aspasasthe autēn</strong> — greet it (the household, using <em>aspasasthe</em> aorist imperative of <em>aspazomai</em>: a formal, extended greeting — not a casual wave but the covenant-greeting of <em>shalom</em>) — in Jewish practice, a spoken blessing upon entering a house was a form of pronouncing peace. The greeting carries theological weight: peace (<em>eirēnē</em>) is not just courtesy but a blessing that may or may not "rest" on the household depending on its receptivity (v.13).</p>',
    "13": '<p><strong>ean men ē hē oikia axia elthatō hē eirēnē hymōn ep autēn</strong> — if the house is worthy, let your peace come upon it (<em>elthatō</em> aorist imperative: let it come) — <em>ean de mē ē axia hē eirēnē hymōn pros hymas epistraphētō</em> (if it is not worthy, let your peace return to you — <em>epistraphētō</em> aorist passive imperative of <em>strephō</em>): peace is not lost when rejected; it returns to the one who offered it. The agents of peace are not diminished by its rejection, but the household forfeits what was offered.</p>',
    "14": '<p><strong>ektinaxtate ton koniorton tōn podōn hymōn</strong> — shake the dust off your feet (<em>ektinassō</em> aorist imperative: to shake out thoroughly) — a gesture of dissociation: by shaking off the town\'s dust, the disciples symbolically return the town\'s guilt to itself. In Jewish practice, Jews shook the dust of Gentile lands from their feet when re-entering Israel; here the gesture is applied to Israelite towns that reject the kingdom-proclamation, treating their refusal as equivalent to Gentile rejection.</p>',
    "15": '<p><strong>anektoteron estai Sodomois kai Gomorrois en hēmera kriseōs</strong> — it will be more bearable for Sodom and Gomorrah on the day of judgment (<em>anektoteros</em>, comparative of <em>anektos</em>: bearable, tolerable) — the comparative establishes gradations of judgment: Sodom and Gomorrah, destroyed for notorious wickedness, face a lighter judgment than the towns of Israel that reject the kingdom-messenger. The logic: responsibility scales with proximity to the gospel; greater revelation produces greater accountability.</p>',
    "16": '<p><strong>idou egō apostellō hymas hōs probata en mesō lykōn</strong> — behold I send you as sheep in the midst of wolves — <em>apostellō</em> (to send on a commission, the verb from which <em>apostolos</em> comes): the sending is Jesus\'s act. <em>Phronimoi hōs hoi opheis kai akeraioi hōs hai peristerai</em> — shrewd as snakes and innocent as doves: <em>phronimos</em> (practically wise, discerning — the same word as the wise builder in 7:24) and <em>akeraios</em> (unmixed, pure, without adulteration: used of unalloyed metal and pure wine). The combination is not cunning-plus-innocence but wisdom-that-does-not-compromise.</p>',
    "17": '<p><strong>paradōsousin hymas eis synedria</strong> — they will hand you over to councils (<em>synedria</em>, plural: local councils with judicial authority, smaller than the Jerusalem Sanhedrin) — <em>kai en tais synagōgais autōn mastigōsousin hymas</em> (and in their synagogues they will flog you: <em>mastigoō</em>, to flog with a whip, the formal punishment of the synagogue court — up to 39 lashes according to Deut 25:3 as interpreted in the Mishnah). The persecution comes from within the covenant community, not only from outsiders.</p>',
    "18": '<p><strong>kai epi hēgemonas de kai basileis achthēsesthe heneken emou</strong> — you will be brought before governors and kings because of me (<em>hēgemōn</em>, governor/prefect like Pilate; <em>basileus</em>, king like Herod) — <em>heneken emou</em> (because of me, on account of me): the persecution is specifically due to association with Jesus, not incidental political trouble. <em>Eis martyrion autois kai tois ethnesin</em> — as a testimony to them and to the Gentiles: the hostile tribunal becomes a platform for witness; suffering produces proclamation.</p>',
    "19": '<p><strong>mē merimnēsēte pōs ē ti lalēsēte</strong> — do not be anxious how or what you will speak (<em>merimnēsēte</em> aorist subjunctive: do not take up this anxiety) — the double question (<em>pōs</em>, how; <em>ti</em>, what) covers both manner and content of speech under pressure. <em>Dothēsetai gar hymin en ekeinē tē hōra ti lalēsēte</em> — for it will be given to you in that hour what to say (<em>dothēsetai</em> future passive divine): the provision is eschatological-moment specific, not a general license to avoid preparation.</p>',
    "20": '<p><strong>ou gar hymeis este hoi lalountes alla to pneuma tou patros hymōn</strong> — for it is not you who speak but the Spirit of your Father (<em>pneuma tou patros hymōn</em>, the Spirit of your Father — Matthew\'s distinctive way of identifying the Spirit, here as the Spirit who belongs to and comes from the Father) — the speaking is genuinely human speech through a genuinely divine agency; both the human subject (<em>hymeis</em>) and the divine subject (<em>to pneuma</em>) are named, not one replacing the other. <em>To laloun en hymin</em> — speaking in/through you.</p>',
    "21": '<p><strong>paradōsei de adelphos adelphon eis thanaton kai patēr teknon</strong> — brother will betray brother to death and a father his child — <em>paradōsei</em> future of <em>paradidōmi</em> (to hand over, deliver up — the same verb used of Judas betraying Jesus; 10:4; 26:16,21): the vocabulary of betrayal applied to family relationships. <em>Epanastēsontai tekna epi goneis</em> — children will rise up against parents (<em>epanistēmi</em>, to rise up against, revolt): the language of insurrection applied to the family structure. This Micah 7:6 echo (cf. v.35-36) anticipates the family-division saying.</p>',
    "22": '<p><strong>kai esesthe misoumenoi hypo pantōn dia to onoma mou</strong> — you will be hated by all on account of my name (<em>misoumenoi</em> present passive participle: ongoing, continuous hatred) — <em>dia to onoma mou</em> (on account of my name): the hatred is not incidental but specifically motivated by association with Jesus. <em>Ho de hypomoinas eis telos sōthēsetai</em> — the one enduring to the end will be saved (<em>hypomeno</em>, to remain under, endure under pressure — not passive resignation but active continuance under weight). <em>Eis telos</em> (to the end): the full duration, wherever the end comes.</p>',
    "23": '<p><strong>hotan de diōkōsin hymas en tē polei tautē, pheugete eis tēn heteran</strong> — when they persecute you in this city, flee to another (<em>pheugete</em> present imperative: continue fleeing as a practice) — <em>ou mē telesēte tas poleis tou Israēl heōs an elthē ho huios tou anthrōpou</em> — you will not finish the cities of Israel before the Son of Man comes (<em>telesēte</em> aorist subjunctive of <em>teleō</em>, to complete; the double negative <em>ou mē</em> for emphatic futurity). The saying\'s precise reference to "the coming of the Son of Man" is debated (the resurrection, Pentecost, the destruction of Jerusalem in 70 CE, or the parousia); the urgency is unambiguous.</p>',
    "24": '<p><strong>ouk estin mathētēs hyper ton didaskalon</strong> — a student is not above the teacher — the proverb establishes the basic order: disciple/teacher, servant/master. <em>Hyper</em> (above, beyond): the comparative locates the disciple permanently below the teacher in standing. The saying grounds the expectation of persecution: if the Teacher was opposed, the disciple should expect no better treatment. The logic is not fatalistic but orienting.</p>',
    "25": '<p><strong>arketon tō mathētē hina genētai hōs ho didaskalos autou</strong> — it is enough for the student to become like his teacher (<em>arketon</em>, sufficient, from <em>arkeō</em>: the same word as 6:34 for the day\'s sufficient trouble) — <em>ei ton oikodespotēn Beelzeboul ekalesian</em> — if they called the master of the house Beelzebul (<em>Beelzeboul</em>: probably from Hebrew <em>Ba\'al Zebul</em>, "lord of the exalted house," though the LXX\'s <em>Baalzebub</em> = "lord of the flies" is also a possible background): they have already called Jesus a demonic ally (9:34; 12:24); the household-members face the same charge.</p>',
    "26": '<p><strong>mē oun phobetheite autous</strong> — therefore do not fear them (<em>phobeō</em> aorist passive subjunctive: do not be made to fear) — the prohibition rests on the certainty of disclosure: <em>ouden gar estin kekalymmenon ho ouk apokalypsthesetai</em> (nothing is covered that will not be uncovered — <em>apokalyptō</em> future passive divine: God will uncover). <em>Kai krupton ho ou gnōsthēsetai</em> — and nothing hidden that will not be known: what is done and said in secret, including the disciples\' private instruction, will be made public in God\'s time.</p>',
    "27": '<p><strong>ho legō hymin en tē skotia eipate en tō phōti</strong> — what I tell you in the darkness, speak in the light — <em>en tē skotia</em> (in the darkness): private, intimate instruction. <em>En tō phōti</em> (in the light): public proclamation. The disciples receive teaching in the private darkness of discipleship-with-Jesus and are to broadcast it publicly. <em>Kai ho eis to ous akouete kērysate epi tōn dōmatōn</em> — and what you hear whispered in the ear, proclaim from the rooftops: from intimate whisper to rooftop announcement — the instruction moves outward and upward in scale.</p>',
    "29": '<p><strong>ouchi dyo strouthia assariou pōleitai</strong> — are not two sparrows sold for an assarion (<em>assarion</em>, the smallest Roman copper coin, worth about 1/16 of a denarius) — the sparrow (<em>strouthion</em>) is the cheapest, most disposable bird in the marketplace. <em>Kai hen ex autōn ou peseitai epi tēn gēn aneu tou patros hymōn</em> — and not one of them will fall to the ground apart from (<em>aneu</em>) your Father: <em>aneu</em> (without, apart from) — not "without the Father\'s permission" but without the Father\'s presence and knowledge. Divine providence extends to the individual fall of the most commercially negligible creature.</p>',
    "30": '<p><strong>hymon de kai hai triches tēs kephalēs pasai ērithmēmenai eisin</strong> — even the hairs of your head are all numbered (<em>ērithmēmenai eisin</em> perfect passive periphrastic: stand numbered, remain in a numbered state) — the perfect participle marks the numbering as a completed and ongoing state, not a one-time count; God\'s knowledge of the disciples is current and complete. The contrast with the sparrow (which is commercially counted at two per assarion) is that the disciples are not priced at all by weight of hair but individually known to the Father.</p>',
    "31": '<p><strong>mē oun phobeisthe pollōn strouthiōn diapherete hymeis</strong> — do not fear therefore; you differ in value from many sparrows (<em>diapherō</em>, to carry through, to differ in worth; used for surpassing value as in 6:26) — the argument is explicit: if the Father\'s providential knowledge extends to sparrows, which are worth less than the disciples, it certainly extends to the disciples. The prohibition on fear (<em>mē phobeisthe</em>) is grounded in the asymmetric valuation: fear is irrational given the Father\'s specific knowledge of each disciple.</p>',
    "32": '<p><strong>pas oun hostis homologēsei en emoi emprosthen tōn anthrōpōn</strong> — everyone who acknowledges me before people (<em>homologeō</em>, to speak the same thing, to confess, to acknowledge openly: the public matching of one\'s speech to the reality of Jesus) — <em>en emoi</em> (in me, using the instrumental <em>en</em>): to confess in Christ is not merely to speak about him but to speak from within the relationship. <em>Homologēsō kagō en autō emprosthen tou patros mou</em> — I will also acknowledge him before my Father: the correspondence is exact — human public acknowledgment answered by Jesus\'s acknowledgment before the Father.</p>',
    "33": '<p><strong>hostis d\'an arnēsētai me emprosthen tōn anthrōpōn</strong> — whoever denies me before people (<em>arneomai</em>: to deny, disown, say no to — the same verb Peter will use in 26:70,72,74) — <em>arnēsomai kagō auton emprosthen tou patros mou</em> (I will also deny him before my Father): the symmetry of vv.32-33 is stark: public acknowledgment → acknowledged by Jesus; public denial → denied by Jesus. The judgment is not punitive addition but the logical extension of the relationship one has chosen to deny.</p>',
    "34": '<p><strong>mē nomisēte hoti ēlthon balein eirēnēn epi tēn gēn</strong> — do not think that I came to throw peace on the earth (<em>balein</em>, to throw, cast — an active, energetic verb: not "to bring peace" gently but to throw it; <em>nomisēte</em>, aorist subjunctive of <em>nomizō</em>, to suppose, think as a matter of convention) — <em>ouk ēlthon balein eirēnēn alla machairan</em> (I came not to throw peace but a sword — <em>machaira</em>, the short single-bladed cutting sword used in daily life and execution). The sword is not Jesus\'s goal but the effect of his presence: the truth he brings forces decisions that divide.</p>',
    "35": '<p><strong>dichazō</strong> — to divide, set at variance (<em>ēlthon dichazai anthrōpon kata tou patros autou</em>, I came to set a man against his father) — the citation of Mic 7:6 frames the family-division as something declared in Scripture, not a new social disruption invented by Jesus. <em>Kai thygatera kata tēs mētros autēs</em> (daughter against her mother) <em>kai nymphēn kata tēs pentheras autēs</em> (daughter-in-law against mother-in-law): the three pairings are intergenerational, covering the household structure.</p>',
    "36": '<p><strong>kai echthroi tou anthrōpou hoi oikiakoi autou</strong> — a person\'s enemies are the members of his household (<em>oikiakoi</em>, household members, those of the same house) — the direct quotation of Mic 7:6 LXX. The verse identifies the source of the opposition named in vv.21-22 (brother against brother, children against parents): those who oppose the disciple because of Jesus are closest in relationship. This is not a sociological observation but an eschatological pressure: the kingdom\'s arrival produces judgment-level divisions within families.</p>',
    "37": '<p><strong>ho philōn patera ē mētera hyper eme ouk estin mou axios</strong> — whoever loves (<em>phileō</em>, to love by natural affection) father or mother more than me is not worthy of me (<em>axios</em>) — <em>phileō</em> is the word for natural, instinctive family love; the verse does not prohibit love of family but addresses priority when the two loyalties conflict. <em>Hyper eme</em> (more than me, beyond me): the comparison is explicit. The same structure governs the son/daughter clause: <em>ho philōn huion ē thygatera hyper eme ouk estin mou axios</em>.</p>',
    "38": '<p><strong>kai hos ou lambanei ton stauron autou kai akolouthei opisō mou</strong> — whoever does not take up his cross and follow after me (<em>lambanei ton stauron</em>, take the cross — <em>lambanō</em> present: ongoing taking up) — the cross as the instrument of execution by crucifixion: a shocking image spoken before the passion narrative, when a person carrying their cross was a condemned person on their way to execution. <em>Opisō mou</em> (after me, behind me): the disciple follows in the direction Jesus has walked, including toward the cross. <em>Ouk estin mou axios</em> — is not worthy of me.</p>',
    "39": '<p><strong>ho heurōn tēn psychēn autou apolesei autēn</strong> — the one who finds his life will lose it (<em>heurōn</em> aorist participle; <em>apolesei</em> future: will destroy/lose it — <em>apollymi</em>, the word for final ruin as well as ordinary losing) — <em>kai ho apolesas tēn psychēn autou heneken emou heurēsei autēn</em> (and whoever loses his life for my sake will find it): the paradox of values operates on <em>psychē</em> (life, soul), a word spanning physical life, personal identity, and the whole self. The one who protects self-life loses it; the one who surrenders it for Jesus finds the real thing.</p>',
    "40": '<p><strong>ho dechomenos hymas eme dechetai</strong> — the one who receives you receives me (<em>dechomai</em>: to receive, welcome as a guest) — the chain of identification: receiving the disciple = receiving Jesus = receiving the one who sent Jesus (<em>ton aposteilanta me</em>, the one who sent me: God). The representative logic makes the disciples\'s reception or rejection a reception or rejection of Jesus himself, and through him of the Father. The same chain appears in reverse in v.33 (denying the disciple ↔ denying Jesus).</p>',
    "41": '<p><strong>ho dechomenos prophētēn eis onoma prophētou misthon prophētou lēmpsetai</strong> — whoever receives a prophet in the name of a prophet will receive a prophet\'s reward (<em>eis onoma prophētou</em>, in the name of a prophet: receiving someone specifically because they are a prophet, in recognition of their prophetic identity) — <em>misthon prophētou</em> (a prophet\'s reward): the same <em>misthos</em> (wage, reward owed) as in 5:12 and 6:1-18. Receiving the prophet because he is a prophet associates the receiver with the prophet\'s mission and its reward.</p>',
    "42": '<p><strong>potērion psychrou hydatos monon</strong> — a cup of cold water only (<em>psychros</em>, cold — cold water is more costly in desert climates, unlike warm water which required no effort to keep warm) — <em>tōn mikrōn toutōn</em> (of these little ones — <em>mikros</em>, small, little: the disciples viewed from the world\'s perspective are small; the diminutive is not derogatory but realistic about their social standing). <em>Ou mē apolese ton misthon autou</em> — will certainly not lose his reward (<em>ou mē</em> + aorist subjunctive: the strongest possible negation of futurity). Even the smallest act of hospitality toward the disciples of Jesus has covenantal weight.</p>'
  }
}

def main():
    existing = load_comm('mkt-original', 'matthew')
    merge_comm(existing, MATTHEW)
    save_comm('mkt-original', 'matthew', existing)
    print('Matthew 9-10 mkt-original written.')

if __name__ == '__main__':
    main()
